import{_ as a,C as i,o as e,c as d,a5 as r,b as s,w as t,a as A,E as n,a4 as E}from"./chunks/framework.gGRxziV4.js";const m=JSON.parse('{"title":"08 - 跨 Harness 适配：一次编写，处处运行","description":"","frontmatter":{},"headers":[],"relativePath":"08-ECC教程/08-跨Harness适配.md","filePath":"08-ECC教程/08-跨Harness适配.md","lastUpdated":null}'),C={name:"08-ECC教程/08-跨Harness适配.md"};function f(p,o,B,u,c,g){const l=i("Mermaid");return e(),d("div",null,[o[4]||(o[4]=r('<h1 id="_08-跨-harness-适配-一次编写-处处运行" tabindex="-1">08 - 跨 Harness 适配：一次编写，处处运行 <a class="header-anchor" href="#_08-跨-harness-适配-一次编写-处处运行" aria-label="Permalink to &quot;08 - 跨 Harness 适配：一次编写，处处运行&quot;">​</a></h1><blockquote><p>你有没有过这种经历：家里有 5 个遥控器，电视一个、空调一个、机顶盒一个、音响一个、投影仪一个。每次想换个台，都得先找遥控器。ECC 的跨 Harness 适配要解决的，就是&quot;一个遥控器控制所有设备&quot;的问题。</p></blockquote><hr><h2 id="真实痛点-你不可能只用一个工具" tabindex="-1">真实痛点：你不可能只用一个工具 <a class="header-anchor" href="#真实痛点-你不可能只用一个工具" aria-label="Permalink to &quot;真实痛点：你不可能只用一个工具&quot;">​</a></h2><p>先说一个残酷的现实：<strong>没有一个 AI 编程工具能满足所有场景</strong>。</p><p>你在终端里写代码时，Claude Code 很好用。但有时候你需要 IDE 的图形化界面——看代码结构、用断点调试、看 Git 历史。这时候 Cursor 可能更合适。又或者你想用开源方案自己魔改，那 OpenCode 是个选择。</p><p>问题是：<strong>每个工具的配置格式都不一样</strong>。</p>',7)),(e(),s(E,null,{default:t(()=>[n(l,{id:"mermaid-21",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20USER%5B%22%F0%9F%A7%91%E2%80%8D%F0%9F%92%BB%20%E4%BD%A0%22%5D%0A%20%20%20%20USER%20--%3E%20CC%5B%22Claude%20Code%5Cn~%2F.claude%2F%22%5D%0A%20%20%20%20USER%20--%3E%20CUR%5B%22Cursor%5Cn.cursor%2F%22%5D%0A%20%20%20%20USER%20--%3E%20OC%5B%22OpenCode%5Cn.opencode%2F%22%5D%0A%0A%20%20%20%20CC%20--%3E%20FMT1%5B%22hooks.json%20%2B%20agents%2F*.md%5Cncommands%2F*.md%22%5D%0A%20%20%20%20CUR%20--%3E%20FMT2%5B%22hooks.json%20%2B%20rules%2F%5Cn.cursorrules%22%5D%0A%20%20%20%20OC%20--%3E%20FMT3%5B%22plugin.ts%20%2B%20opencode.json%5Cncommands%2F%22%5D%0A%0A%20%20%20%20style%20USER%20fill%3A%231a237e%2Ccolor%3A%23fff%0A%20%20%20%20style%20CC%20fill%3A%2342a5f5%2Ccolor%3A%23fff%0A%20%20%20%20style%20CUR%20fill%3A%2366bb6a%2Ccolor%3A%23fff%0A%20%20%20%20style%20OC%20fill%3A%23ff9800%2Ccolor%3A%23fff%0A%20%20%20%20style%20FMT1%20fill%3A%23e3f2fd%2Cstroke%3A%2342a5f5%0A%20%20%20%20style%20FMT2%20fill%3A%23e8f5e9%2Cstroke%3A%2366bb6a%0A%20%20%20%20style%20FMT3%20fill%3A%23fff3e0%2Cstroke%3A%23ff9800%0A"})]),fallback:t(()=>[...o[0]||(o[0]=[A(" Loading... ",-1)])]),_:1})),o[5]||(o[5]=r('<p>想象一下：你精心配好了一套规则——&quot;代码风格用 Prettier，测试用 Jest，提交前跑 lint&quot;。现在你想在另一个工具里也用同样的规则，你得手动把配置&quot;翻译&quot;成另一种格式。</p><p>一个规则要维护三份，十个规则就是三十份。<strong>这不是人干的活</strong>。</p><p>ECC 的核心理念就是：<strong>别让我重复劳动</strong>。我写一份配置，你帮我适配到所有平台。</p><hr><h2 id="为什么选-manifest-driven-安装" tabindex="-1">为什么选 Manifest-Driven 安装？ <a class="header-anchor" href="#为什么选-manifest-driven-安装" aria-label="Permalink to &quot;为什么选 Manifest-Driven 安装？&quot;">​</a></h2><p>你可能会想：&quot;为什么不把所有配置一股脑全复制过去？&quot;</p><p>好问题。我们来类比一下：你搬家的时候，是把家里所有东西都搬到新家，还是挑需要的带？</p><p><strong>全复制的问题</strong>：</p><ul><li>你是一个 Python 开发者，安装后发现多了一堆 TypeScript 的 lint 规则——完全用不上，还浪费 token</li><li>你做纯前端，安装后多了一堆 Go 的 build resolver 配置——噪音太多</li><li>每次 AI 处理配置时都要读一遍这些无关内容，<strong>白白消耗计算资源</strong></li></ul><p>ECC 的做法是 <strong>Manifest-Driven（清单驱动）安装</strong>：</p>',10)),(e(),s(E,null,{default:t(()=>[n(l,{id:"mermaid-64",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20MANIFEST%5B%22%F0%9F%93%8B%20Manifest%5Cn%E5%AE%89%E8%A3%85%E6%B8%85%E5%8D%95%22%5D%0A%20%20%20%20MANIFEST%20--%3E%20A%5B%22%E2%9C%85%20agent-planner%5Cn%E9%9C%80%E8%A6%81%22%5D%0A%20%20%20%20MANIFEST%20--%3E%20B%5B%22%E2%9C%85%20rules%2Ftypescript%5Cn%E9%9C%80%E8%A6%81%22%5D%0A%20%20%20%20MANIFEST%20--%3E%20C%5B%22%E2%9D%8C%20rules%2Fgo%5Cn%E4%B8%8D%E9%9C%80%E8%A6%81%22%5D%0A%20%20%20%20MANIFEST%20--%3E%20D%5B%22%E2%9C%85%20hooks%2Fpre-commit%5Cn%E9%9C%80%E8%A6%81%22%5D%0A%20%20%20%20MANIFEST%20--%3E%20E%5B%22%E2%9D%8C%20hooks%2Fgo-test%5Cn%E4%B8%8D%E9%9C%80%E8%A6%81%22%5D%0A%0A%20%20%20%20A%20--%3E%20OUT%5B%22%F0%9F%93%A6%20%E6%9C%80%E7%BB%88%E5%AE%89%E8%A3%85%E7%BB%93%E6%9E%9C%5Cn%E5%8F%AA%E8%A3%85%E9%9C%80%E8%A6%81%E7%9A%84%22%5D%0A%20%20%20%20B%20--%3E%20OUT%0A%20%20%20%20D%20--%3E%20OUT%0A%0A%20%20%20%20style%20MANIFEST%20fill%3A%231a237e%2Ccolor%3A%23fff%0A%20%20%20%20style%20OUT%20fill%3A%234caf50%2Ccolor%3A%23fff%0A%20%20%20%20style%20C%20fill%3A%23ffcdd2%2Cstroke%3A%23f44336%0A%20%20%20%20style%20E%20fill%3A%23ffcdd2%2Cstroke%3A%23f44336%0A"})]),fallback:t(()=>[...o[1]||(o[1]=[A(" Loading... ",-1)])]),_:1})),o[6]||(o[6]=r('<p>就像你去宜家买家具，不是把整个仓库搬回家，而是拿一张购物清单，按需挑选。Manifest 就是这张清单——它告诉安装器&quot;这个项目需要哪些组件&quot;，安装器只装清单上有的东西。</p><p><strong>好处</strong>：</p><ul><li>🎯 <strong>精准</strong> — 只装你需要的，不装多余的</li><li>💰 <strong>省 token</strong> — AI 不用处理无关配置</li><li>🔇 <strong>安静</strong> — 没有噪音干扰</li><li>🔄 <strong>灵活</strong> — 不同项目可以有不同的清单</li></ul><hr><h2 id="profile-体系-五种用户画像" tabindex="-1">Profile 体系：五种用户画像 <a class="header-anchor" href="#profile-体系-五种用户画像" aria-label="Permalink to &quot;Profile 体系：五种用户画像&quot;">​</a></h2><p>有了 Manifest，下一个问题是：&quot;我怎么知道该选哪些组件？&quot;</p><p>大部分用户不想自己一个个挑。就像你去餐厅，虽然可以单点，但更多人喜欢直接选套餐——&quot;给我来个招牌套餐&quot;。</p><p>ECC 设计了 5 个 Profile，对应 5 种典型的用户画像：</p>',8)),(e(),s(E,null,{default:t(()=>[n(l,{id:"mermaid-106",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20START%5B%22%F0%9F%A4%94%20%E4%BD%A0%E6%98%AF%E5%93%AA%E7%A7%8D%E7%94%A8%E6%88%B7%EF%BC%9F%22%5D%0A%20%20%20%20START%20--%3E%20P1%5B%22%F0%9F%A5%97%20core%5Cn%E5%8F%AA%E6%83%B3%E5%BF%AB%E9%80%9F%E4%B8%8A%E6%89%8B%5Cn%E6%A0%B8%E5%BF%83%20Agent%20%2B%20%E5%BF%85%E5%A4%87%20Skill%22%5D%0A%20%20%20%20START%20--%3E%20P2%5B%22%F0%9F%8D%9D%20developer%5Cn%E6%97%A5%E5%B8%B8%E5%BC%80%E5%8F%91%E9%9C%80%E8%A6%81%E8%A7%84%E8%8C%83%5Cncore%20%2B%20Rules%20%2B%20Commands%22%5D%0A%20%20%20%20START%20--%3E%20P3%5B%22%F0%9F%94%92%20security%5Cn%E6%B3%A8%E9%87%8D%E5%AE%89%E5%85%A8%E5%90%88%E8%A7%84%5Cncore%20%2B%20%E5%AE%89%E5%85%A8%20Rules%20%2B%20%E5%AE%A1%E8%AE%A1%20Hooks%22%5D%0A%20%20%20%20START%20--%3E%20P4%5B%22%F0%9F%94%AC%20research%5Cn%E5%81%9A%E7%A0%94%E7%A9%B6%E5%92%8C%E5%AE%9E%E9%AA%8C%5Cncore%20%2B%20%E6%95%B0%E6%8D%AE%E5%88%86%E6%9E%90%20Skill%22%5D%0A%20%20%20%20START%20--%3E%20P5%5B%22%F0%9F%8D%95%20full%5Cn%E4%BB%80%E4%B9%88%E9%83%BD%E8%A6%81%5Cn%E5%85%A8%E9%83%A8%E7%BB%84%E4%BB%B6%22%5D%0A%0A%20%20%20%20style%20START%20fill%3A%231a237e%2Ccolor%3A%23fff%0A%20%20%20%20style%20P1%20fill%3A%23e3f2fd%2Cstroke%3A%2342a5f5%0A%20%20%20%20style%20P2%20fill%3A%23e8f5e9%2Cstroke%3A%2366bb6a%0A%20%20%20%20style%20P3%20fill%3A%23fce4ec%2Cstroke%3A%23e91e63%0A%20%20%20%20style%20P4%20fill%3A%23f3e5f5%2Cstroke%3A%23ab47bc%0A%20%20%20%20style%20P5%20fill%3A%23fff3e0%2Cstroke%3A%23ff9800%0A"})]),fallback:t(()=>[...o[2]||(o[2]=[A(" Loading... ",-1)])]),_:1})),o[7]||(o[7]=r('<p><strong>为什么是 5 个，不是 3 个或 10 个？</strong></p><p>这是设计上的取舍：</p><ul><li><strong>太少（3 个）</strong>：覆盖不够，用户找不到合适的，还得自己拼</li><li><strong>太多（10 个）</strong>：选择困难症犯了，用户反而不知道选哪个</li><li><strong>5 个</strong>：刚好覆盖主流需求，选择成本低</li></ul><p>这跟手机的颜色策略一样——黑白灰必有，加一两个特色色，够了。</p><p><strong>对你自己项目的启发</strong>：如果你在做一个配置系统，别急着给用户无限的自由。先定义几个&quot;刚好够用&quot;的预设，让用户能快速上手，然后再给高级用户自定义的空间。</p><hr><h2 id="适配层-翻译官-而不是五套话术" tabindex="-1">适配层：翻译官，而不是五套话术 <a class="header-anchor" href="#适配层-翻译官-而不是五套话术" aria-label="Permalink to &quot;适配层：翻译官，而不是五套话术&quot;">​</a></h2><p>这是整个跨 Harness 适配中最精妙的部分。</p><p>每个平台都有自己的&quot;方言&quot;：</p><ul><li><strong>Claude Code</strong> 用 <code>hooks.json</code> 定义事件钩子</li><li><strong>Cursor</strong> 用 <code>hooks.js</code>（JavaScript 文件）</li><li><strong>OpenCode</strong> 用 <code>plugin.ts</code>（TypeScript 插件）</li></ul><p>如果你为每个平台都写一遍逻辑，那就是五套代码做同一件事——维护噩梦。</p><p>ECC 的做法是：<strong>写一套核心逻辑 + 一个翻译层</strong>。</p>',12)),(e(),s(E,null,{default:t(()=>[n(l,{id:"mermaid-169",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20CORE%5B%22%F0%9F%A7%A0%20ECC%20%E6%A0%B8%E5%BF%83%E9%80%BB%E8%BE%91%5Cn%E4%B8%80%E4%BB%BD%E4%BB%A3%E7%A0%81%EF%BC%8C%E4%B8%80%E7%A7%8D%E9%80%BB%E8%BE%91%22%5D%0A%20%20%20%20CORE%20--%3E%20ADAPTER%5B%22%F0%9F%94%84%20%E9%80%82%E9%85%8D%E5%B1%82%EF%BC%88%E7%BF%BB%E8%AF%91%E5%AE%98%EF%BC%89%22%5D%0A%20%20%20%20ADAPTER%20--%3E%20T1%5B%22Claude%20Code%20%E9%80%82%E9%85%8D%E5%99%A8%5Cn%E8%BE%93%E5%87%BA%20hooks.json%5Cn%2B%20agents%2F*.md%22%5D%0A%20%20%20%20ADAPTER%20--%3E%20T2%5B%22Cursor%20%E9%80%82%E9%85%8D%E5%99%A8%5Cn%E8%BE%93%E5%87%BA%20hooks.js%5Cn%2B%20.cursorrules%22%5D%0A%20%20%20%20ADAPTER%20--%3E%20T3%5B%22OpenCode%20%E9%80%82%E9%85%8D%E5%99%A8%5Cn%E8%BE%93%E5%87%BA%20plugin.ts%5Cn%2B%20opencode.json%22%5D%0A%20%20%20%20ADAPTER%20--%3E%20T4%5B%22Codex%20%E9%80%82%E9%85%8D%E5%99%A8%5Cn%E8%BE%93%E5%87%BA%20AGENTS.md%5Cn%2B%20config.toml%22%5D%0A%20%20%20%20ADAPTER%20--%3E%20T5%5B%22%E5%85%B6%E4%BB%96%E5%B9%B3%E5%8F%B0%E9%80%82%E9%85%8D%E5%99%A8%5Cn%E6%8C%89%E9%9C%80%E6%89%A9%E5%B1%95%22%5D%0A%0A%20%20%20%20style%20CORE%20fill%3A%231a237e%2Ccolor%3A%23fff%0A%20%20%20%20style%20ADAPTER%20fill%3A%2378909c%2Ccolor%3A%23fff%0A%20%20%20%20style%20T1%20fill%3A%2342a5f5%2Ccolor%3A%23fff%0A%20%20%20%20style%20T2%20fill%3A%2366bb6a%2Ccolor%3A%23fff%0A%20%20%20%20style%20T3%20fill%3A%23ff9800%2Ccolor%3A%23fff%0A%20%20%20%20style%20T4%20fill%3A%23ab47bc%2Ccolor%3A%23fff%0A%20%20%20%20style%20T5%20fill%3A%2390a4ae%2Ccolor%3A%23fff%0A"})]),fallback:t(()=>[...o[3]||(o[3]=[A(" Loading... ",-1)])]),_:1})),o[8]||(o[8]=r('<p>这就是软件工程中经典的 <strong>适配器模式（Adapter Pattern）</strong>。打个比方：</p><p>你是一个中国人，要跟美国人、日本人、法国人做生意。你不需要学会说四国语言——你只需要雇四个翻译。核心谈判逻辑是一样的，变的只是语言。</p><p><strong>适配器模式的好处</strong>：</p><ul><li>✅ <strong>加新平台很容易</strong> — 写一个新的适配器就行，不用动核心逻辑</li><li>✅ <strong>改核心逻辑很安全</strong> — 改一处，所有平台自动更新</li><li>✅ <strong>维护成本低</strong> — 只维护一套核心 + 几个薄薄的翻译层</li></ul><p><strong>对你自己项目的启发</strong>：如果你的系统要支持多个下游平台/格式，先把核心逻辑抽出来，然后为每个平台写一个适配器。别把平台相关的代码混在核心逻辑里——那是技术债的温床。</p><hr><h2 id="实际效果-一套配置-五个平台" tabindex="-1">实际效果：一套配置，五个平台 <a class="header-anchor" href="#实际效果-一套配置-五个平台" aria-label="Permalink to &quot;实际效果：一套配置，五个平台&quot;">​</a></h2><p>来看看一个真实的配置在不同平台上的&quot;翻译&quot;效果：</p><table tabindex="0"><thead><tr><th>配置内容</th><th>Claude Code</th><th>Cursor</th><th>OpenCode</th></tr></thead><tbody><tr><td>&quot;提交前跑 lint&quot;</td><td><code>hooks.json</code> 里加 <code>preCommit</code></td><td><code>hooks.js</code> 里加 <code>onBeforeCommit</code></td><td><code>plugin.ts</code> 里加 <code>preCommit</code> 事件</td></tr><tr><td>&quot;Agent 角色定义&quot;</td><td><code>agents/planner.md</code></td><td><code>.cursor/rules/planner.mdc</code></td><td><code>agents/planner.ts</code></td></tr><tr><td>&quot;自定义命令&quot;</td><td><code>commands/review.md</code></td><td><code>.cursor/commands/review.md</code></td><td><code>commands/review.ts</code></td></tr></tbody></table><p><strong>核心内容完全一样</strong>，只是&quot;穿了不同的衣服&quot;。</p><hr><h2 id="对你项目的启发" tabindex="-1">对你项目的启发 <a class="header-anchor" href="#对你项目的启发" aria-label="Permalink to &quot;对你项目的启发&quot;">​</a></h2><p>读到这里，你可能已经想到了自己的场景。不管你在做什么项目，跨适配的思路都是通用的：</p><ol><li><strong>先抽象核心</strong> — 把&quot;不管在哪个平台都一样的东西&quot;抽出来</li><li><strong>再写适配器</strong> — 为每个平台写一个薄薄的翻译层</li><li><strong>用清单驱动</strong> — 别全复制，按需安装</li><li><strong>提供预设</strong> — 给用户几个&quot;套餐&quot;，降低选择成本</li></ol><p>这套方法论，从配置管理到 API 网关，从跨平台 App 到多云部署，处处都能用。</p><hr><h2 id="小结" tabindex="-1">小结 <a class="header-anchor" href="#小结" aria-label="Permalink to &quot;小结&quot;">​</a></h2><p>ECC 的跨 Harness 适配解决了三个真实痛点：</p><ul><li>🎯 <strong>维护多套配置太累</strong> → 一次编写，自动翻译</li><li>📦 <strong>全量安装太吵</strong> → Manifest 驱动，按需安装</li><li>🍽️ <strong>不知道装什么</strong> → 5 个 Profile，快速上手</li></ul><p>背后的工程智慧是适配器模式——核心逻辑和平台实现分离，让系统可以低成本地扩展到新平台。</p><p>下一篇，我们来看看支撑这一切的工程基础设施——那些你平时看不见，但让一切运转如常的&quot;幕后英雄&quot;。</p><hr><p><em>上一篇：<a href="./07-Rules系统.html">07-Rules 系统</a> | 下一篇：<a href="./09-工程基础设施.html">09-工程基础设施</a></em></p>',23))])}const D=a(C,[["render",f]]);export{m as __pageData,D as default};
